Query: 用 JavaScript 写一个函数 debounce(fn, delay)，返回一个防抖版本的函数。
Response: ```javascript
/**
 * 创建一个防抖函数，延迟执行传入的函数。
 * 在指定的延迟时间内重复调用会重置定时器，只有最后一次调用才会在延迟结束后执行。
 *
 * @param {Function} fn - 需要防抖的函数
 * @param {number} delay - 延迟时间（毫秒）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay) {
  let timerId = null;

  return function (...args) {
    // 清除上一次的定时器
    if (timerId !== null) {
      clearTimeout(timerId);
    }

    // 设置新的定时器
    timerId = setTimeout(() => {
      // 保留正确的 this 上下文
      fn.apply(this, args);
      timerId = null; // 执行后重置定时器 ID（可选，便于垃圾回收）
    }, delay);
  };
}

// 使用示例（仅供说明）：
// const log = debounce((msg) => console.log(msg), 500);
// log('hello'); // 只有停止调用 500ms 后才会输出
```

